import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.DXGyWiRo.js";const r="/assets/image%20(35).CxXjlvxC.",s="/assets/image%20(36).DIZin6uz.",n="/assets/image%20(37).wLrZ-xCM.",c="/assets/image%20(38).Bio4XBvD.",d="/assets/image%20(39).ztmKIho2.",l="/assets/image%20(40).BLls_0md.",m="/assets/image%20(41).C0-kxLwG.",p="/assets/image%20(42).CwVh_L06.",g="/assets/image%20(43).yZfdaYc7.",h="/assets/image%20(44).BPU3UpWK.",u="/assets/image%20(45).BfeNReL9.",_=JSON.parse('{"title":"Using ChatGPT to build system diagrams — Part II","description":"","frontmatter":{},"headers":[],"relativePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/from-google-sheets-how-to-send-email-based-on-date/using-chatgpt-to-build-system-diagrams-part-ii.md","filePath":"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/from-google-sheets-how-to-send-email-based-on-date/using-chatgpt-to-build-system-diagrams-part-ii.md"}'),f={name:"misc/tutorials/setting-up-k3s-in-lxc-containers-using-netmaker/install-k3s/from-google-sheets-how-to-send-email-based-on-date/using-chatgpt-to-build-system-diagrams-part-ii.md"};function b(k,e,P,v,y,w){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="using-chatgpt-to-build-system-diagrams-—-part-ii" tabindex="-1">Using ChatGPT to build system diagrams — Part II <a class="header-anchor" href="#using-chatgpt-to-build-system-diagrams-—-part-ii" aria-label="Permalink to &quot;Using ChatGPT to build system diagrams — Part II&quot;">​</a></h1><p>Continuing from my <a href="https://aruva.medium.com/using-chatgpt-to-build-system-diagrams-part-i-69efc7603926" target="_blank" rel="noreferrer">previous post</a>, I wanted to focus on the <a href="https://c4model.com/" target="_blank" rel="noreferrer">C4 diagramming model</a>. To keep ChatGPT from deviating from the intention, I started with this prompt:</p><blockquote><p><strong>Prompt</strong>: Going forward, I want you to act as a software architect and build C4 diagrams using mermaid.js. Keep the answers to markdown syntax and always keep in mind software functional and non-functional aspects including but not limited to scalability, availability, redundancy, containerization, security and disaster recovery.</p><p><strong>ChatGPT</strong>: Sure, as a software architect, I can help you create C4 diagrams using Mermaid.js that take into account functional and non-functional aspects such as scalability, availability, redundancy, containerization, security, and disaster recovery.</p></blockquote><p>C4 diagrams are a way to represent the architecture of a software system and are divided into four main levels:</p><ul><li>Context level — external factors that interact with the system</li><li>Container level — deployment units and their dependencies</li><li>Component level — different components of the system</li><li>Code level — implementation details of the system</li></ul><h2 id="context-diagram" tabindex="-1">Context Diagram <a class="header-anchor" href="#context-diagram" aria-label="Permalink to &quot;Context Diagram&quot;">​</a></h2><blockquote><p><strong>Prompt</strong>: Let’s start by creating a context diagram of the services in Wealth Management<br><strong>ChatGPT</strong>: Sure, here’s an example of a context diagram in Mermaid format for a Wealth Management System:</p></blockquote><p><img src="'+r+'" alt=""></p><p>context diagram</p><p>and in the markdown editor</p><p><img src="'+s+'" alt=""></p><p>context diagram</p><p>This diagram shows the main actors that interact with the Wealth Management System and the main services provided by the system.</p><ul><li>The <code>User</code> interacts with the <code>Account Management Service</code>, <code>Portfolio Management Service</code>, <code>Asset Management Service</code>, and <code>Transaction Management Service</code>.</li><li>The <code>Financial Institution</code> also interacts with the <code>Account Management Service</code>, <code>Portfolio Management Service</code>, <code>Asset Management Service</code>, and <code>Transaction Management Service</code>.</li><li>The <code>Market</code> interacts with the <code>Market Data Service</code>.</li></ul><p>This gives an overview of the main interactions between actors and services, useful for understanding the high-level architecture.</p><h3 id="container-diagram" tabindex="-1">Container Diagram <a class="header-anchor" href="#container-diagram" aria-label="Permalink to &quot;Container Diagram&quot;">​</a></h3><p>Looks good so far. Next, let’s build a container-level diagram for one of the services.</p><blockquote><p><strong>Prompt</strong>: Let’s take the Portfolio service and break it down by creating a container diagram for its sub-functionalities<br><strong>ChatGPT</strong>: Sure, here’s an example of a container diagram in Mermaid format for the Portfolio Management Service of a Wealth Management System:</p></blockquote><p><img src="'+n+'" alt=""></p><p>Container diagram</p><p>and markdown diagram</p><p><img src="'+c+'" alt=""></p><p>This diagram shows the containers that comprise the Portfolio Management Service and their dependencies.</p><ul><li>The <code>Portfolio Management API</code> is the entry point for the users and other systems to interact with the service.</li><li>The <code>Portfolio Management Worker</code> performs background tasks like updating portfolios based on market changes.</li><li>The <code>Portfolio Management Database</code> stores portfolio-related data, such as assets and current value.</li><li>The <code>Load Balancer</code> distributes incoming traffic among instances of the <code>Portfolio Management API</code> running in the <code>Kubernetes Cluster</code>.</li><li>The <code>Kubernetes Cluster</code> manages scaling, availability, and deployment of the containers.</li></ul><h3 id="component-diagram" tabindex="-1">Component Diagram <a class="header-anchor" href="#component-diagram" aria-label="Permalink to &quot;Component Diagram&quot;">​</a></h3><blockquote><p><strong>Prompt</strong>: Next lets create the component level diagram for portfolio management api with all relevant details<br><strong>ChatGPT</strong>: Here’s an example of a component diagram in Mermaid format for the Portfolio Management API</p></blockquote><p><img src="'+d+'" alt=""></p><p>and the corresponding mermaid diagram</p><p><img src="'+l+'" alt=""></p><p>Component diagram for Portfolio Management API</p><p>Description:</p><ul><li><code>API Gateway</code> — entry point for incoming requests.</li><li><code>Authentication</code> — authenticates users.</li><li><code>Authorization</code> — checks user access rights.</li><li><code>Request Validator</code> — validates incoming requests.</li><li><code>Business Logic</code> — processes requests and applies business rules.</li><li><code>Response Formatter</code> — formats responses sent to clients.</li><li><code>Portfolio Service</code> — performs CRUD operations for portfolios and communicates with the <code>Portfolio Management Database</code>.</li></ul><p>Follow-up:</p><blockquote><p><strong>Prompt</strong>: can we do the same for portfolio management worker container<br><strong>ChatGPT</strong>: Sure, here’s an example of a component diagram in Mermaid format for the Portfolio Management Worker container:</p></blockquote><p><img src="'+m+'" alt=""></p><p>and the mermaid diagram</p><p><img src="'+p+'" alt=""></p><p>Component Diagram for Portfolio Management Worker</p><ul><li><code>Task Scheduler</code> — schedules background tasks to update portfolios.</li><li><code>Portfolio Updater</code> — updates portfolios based on market changes; communicates with <code>Market Data Service</code>.</li><li><code>Market Data Service</code> — provides market data to the updater.</li><li><code>Portfolio Service</code> — performs portfolio management operations and persists data to the <code>Portfolio Management Database</code>.</li></ul><h3 id="code-diagram" tabindex="-1">Code Diagram <a class="header-anchor" href="#code-diagram" aria-label="Permalink to &quot;Code Diagram&quot;">​</a></h3><blockquote><p><strong>Prompt:</strong> Can you also do the code diagram for Portfolio Management API<br><strong>ChatGPT</strong>: Sure, here’s an example of a code diagram in Mermaid format for the Portfolio Management API:</p></blockquote><p><img src="'+g+'" alt=""></p><p>However, when creating this in the markdown editor with Mermaid.js, it failed to indicate cyclical dependencies. The corrected graph removes those cycles:</p><p><img src="'+h+'" alt=""></p><p>Corrected Code Graph</p><p>and the mermaid diagram</p><p><img src="'+u+'" alt=""></p><p>Portfolio Management API code packages:</p><ul><li><code>api</code> — entry point, defines routes and middleware.</li><li><code>auth</code> — handles authentication and authorization.</li><li><code>config</code> — loads configuration files.</li><li><code>controllers</code> — handles requests and calls services.</li><li><code>errors</code> — defines custom errors.</li><li><code>middleware</code> — provides middleware (CORS, request validation, etc.).</li><li><code>models</code> — defines ORM models for database entities.</li><li><code>services</code> — performs business logic and communicates with the database.</li><li><code>utils</code> — utility functions.</li></ul><p>This was a blog post to depict the capabilities of ChatGPT, especially on the C4 diagramming model. Thanks for reading!</p><p>Interested in Mindmaps — read the blog post on using PlantUML with ChatGPT to create awesome Mindmaps: <a href="https://link.medium.com/q5YglIQ74wb" target="_blank" rel="noreferrer">https://link.medium.com/q5YglIQ74wb</a></p><p>Last updated 2 years ago</p>',52)])])}const M=t(f,[["render",b]]);export{_ as __pageData,M as default};
